spec.inputArgumentsSchemaV2:
{
        "type": "object",
        "required": [
          "partyName"
        ],
        "properties": {
          "partyName": {
            "type": "string",
            "description": "Full legal name of the party to screen (individual, company, or vessel)"
          },
          "partyType": {
            "type": "string",
            "description": "Party type: Individual, Entity, Vessel, or Aircraft. Leave empty to search all types."
          },
          "partyCountry": {
            "type": "string",
            "description": "Country of the party (ISO 2-letter code, e.g. CN, RU, IR). Used for context."
          },
          "partyAddress": {
            "type": "string",
            "description": "Address or city of the party. Used for disambiguation."
          }
        }
      }

spec.outputArgumentsSchemaV2:
{
        "type": "object",
        "properties": {
          "hitStatus": {
            "type": "string",
            "description": "Screening result: CONFIRMED_HIT, POTENTIAL_MATCH, or CLEAR"
          },
          "matchScore": {
            "type": "integer",
            "description": "Highest fuzzy match score from OFAC SDN list (0-100)"
          },
          "riskLevel": {
            "type": "string",
            "description": "Risk assessment: HIGH, MEDIUM, LOW, or NONE"
          },
          "matchedEntries": {
            "type": "array",
            "description": "List of matched SDN entries with name, type, and score",
            "items": {
              "type": "object"
            }
          },
          "recommendation": {
            "type": "string",
            "description": "Compliance action recommendation: BLOCK, ESCALATE, MANUAL_REVIEW, or APPROVE"
          },
          "rawSearchResults": {
            "type": "string",
            "description": "Raw JSON results from OFAC SDN API search"
          }
        }
      }

